//! XSS/HTML5 blacklists — **mechanically generated** from the static arrays
//! `BLACKATTREVENT`, `BLACKATTR`, and `BLACKTAG` in libinjection's
//! `src/libinjection_xss.c` (BSD-3; see `data/ATTRIBUTION.md`). Do not edit by
//! hand: regenerate from the C source to preserve the exact order and casing the
//! C lookup relies on. The `BLACKATTREVENT` entries are keyed on the attribute
//! name with the leading `on` stripped (matches the C lookup against `&s[2]`).

/// Attribute classification (`attribute_t` in libinjection_xss.c).
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum AttrType {
    /// `TYPE_NONE` — not blacklisted.
    None,
    /// `TYPE_BLACK` — ban always.
    Black,
    /// `TYPE_ATTR_URL` — attribute value takes a URL-like object.
    AttrUrl,
    /// `TYPE_STYLE`.
    Style,
    /// `TYPE_ATTR_INDIRECT` — attribute *name* is given in *value*.
    AttrIndirect,
}

